def authenticate(user, password):
    """Validate a user's credentials against the auth backend."""
    return user.password_hash == hash_password(password)


def issue_jwt(user, scopes):
    """Mint a 15-minute access token plus a 30-day refresh token."""
    return mint_token(user.id, scopes, ttl_seconds=900)

